/**
 * 仅清理 api.js 使用的本地 Storage 缓存键
 * 供 app.js 调用，避免启动时 require 整份 api.js
 */
const { CACHE_PREFIX, CACHE_DURATION } = require('./cache-constants.js')

/**
 * 分片清理，避免 keys 较多时连续 sync IO 卡住主线程（模拟器易报无响应）
 */
function cleanExpiredApiCache() {
  let keys = []
  try {
    keys = wx.getStorageInfoSync().keys.filter((k) => k.startsWith(CACHE_PREFIX))
  } catch (e) {
    return
  }
  if (!keys.length) return

  const now = Date.now()
  const BATCH = 8
  let i = 0

  const step = () => {
    const end = Math.min(i + BATCH, keys.length)
    for (; i < end; i++) {
      const key = keys[i]
      // 改用异步读取，避免阻塞主线程
      wx.getStorage({
        key: key,
        success: (res) => {
          const cacheData = res.data
          if (cacheData && now - cacheData.timestamp > CACHE_DURATION) {
            wx.removeStorage({ key: key })
          }
        },
        fail: () => {
          // key 读取失败，尝试清除
          try { wx.removeStorage({ key: key }) } catch (err) {}
        }
      })
    }
    if (i < keys.length) {
      setTimeout(step, 50)
    }
  }
  setTimeout(step, 100)
}

/**
 * 一次性清理旧 slim schema 版本的列表缓存（_slim 和 _slim_v2）
 *
 * 背景：列表瘦身 schema 升级到 _slim_v3 后，老版本缓存里的数据缺了
 * landing.success 等关键字段，会让历史任务回收图标颜色永远是白色。
 * 新代码用新 key 读取，但 storage 里旧 key 仍然占用空间，而且
 * _buildCandidateKeys 的兜底回退会命中它们 → 误用老数据。
 *
 * 这里在 app 启动时调用一次，把老 key 清掉，等新缓存到来就行。
 */
function cleanLegacySlimCache() {
  let keys = []
  try {
    keys = wx.getStorageInfoSync().keys.filter((k) =>
      k.startsWith(CACHE_PREFIX) && (k.endsWith('_slim') || k.endsWith('_slim_v2'))
    )
  } catch (e) {
    return
  }
  if (!keys.length) return

  const BATCH = 8
  let i = 0
  const step = () => {
    const end = Math.min(i + BATCH, keys.length)
    for (; i < end; i++) {
      try { wx.removeStorage({ key: keys[i] }) } catch (err) {}
    }
    if (i < keys.length) {
      setTimeout(step, 50)
    }
  }
  setTimeout(step, 100)
}

module.exports = {
  cleanExpiredApiCache,
  cleanLegacySlimCache,
  CACHE_PREFIX,
  CACHE_DURATION
}
